import 'react-native-gesture-handler';
import React, { useCallback, useEffect } from 'react';
import { ActivityIndicator, View, StyleSheet, Platform, useWindowDimensions } from 'react-native';
import { SafeAreaProvider } from 'react-native-safe-area-context';
import { StripeProvider } from '@stripe/stripe-react-native';
import AppNavigator from './src/navigation/AppNavigator';
import { AuthProvider } from './src/context/AuthContext';
import { CartProvider } from './src/context/CartContext';
import { SettingsProvider } from './src/context/SettingsContext';
import { NetworkProvider } from './src/context/NetworkContext';
import NetworkBanner from './src/components/NetworkBanner';
import { GestureHandlerRootView } from 'react-native-gesture-handler';
import { LinearGradient } from 'expo-linear-gradient';
import * as Font from 'expo-font';

/**
 * Responsive breakpoints:
 *   Mobile:  width <= 480   → full-width, no wrapper
 *   Tablet:  481 – 1024    → centered, max 600px
 *   Desktop: > 1024        → centered, max 480px (app-like column)
 */
function getContainerMaxWidth(screenWidth: number): number | undefined {
  if (screenWidth <= 480) return undefined;      // full-width on phones
  if (screenWidth <= 1024) return 600;           // tablet
  return 480;                                    // desktop – mobile-app column
}

export default function App() {
  const stripeKey = process.env.EXPO_PUBLIC_STRIPE_PUBLISHABLE_KEY || "pk_test_dummy_key";
  const { width: windowWidth } = useWindowDimensions();

  const [fontsLoaded, setFontsLoaded] = React.useState(false);

  const loadFonts = useCallback(async () => {
    await Font.loadAsync({
      Inter: require('./assets/fonts/Inter-Regular.ttf'),
      'Inter-Bold': require('./assets/fonts/Inter-Bold.ttf'),
    });
    setFontsLoaded(true);
  }, []);

  React.useEffect(() => {
    loadFonts();
  }, []);

  // Inject viewport meta tag and body styles for web
  useEffect(() => {
    if (Platform.OS === 'web' && typeof document !== 'undefined') {
      // Set viewport meta tag
      let meta = document.querySelector('meta[name="viewport"]');
      if (!meta) {
        meta = document.createElement('meta');
        meta.setAttribute('name', 'viewport');
        document.head.appendChild(meta);
      }
      meta.setAttribute('content', 'width=device-width, initial-scale=1, maximum-scale=5, user-scalable=yes');

      // Style body/html to center the app
      document.documentElement.style.height = '100%';
      document.documentElement.style.overflow = 'hidden';
      document.body.style.height = '100%';
      document.body.style.overflow = 'hidden';
      document.body.style.margin = '0';
      document.body.style.display = 'flex';
      document.body.style.justifyContent = 'center';
      document.body.style.backgroundColor = '#0f2027';
    }
  }, []);

  if (!fontsLoaded) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  const appContent = (
    <GestureHandlerRootView style={{ flex: 1 }}>
      <LinearGradient colors={['#0f2027', '#203a43', '#2c5364']} style={styles.gradient}>
        <StripeProvider publishableKey={stripeKey}>
          <AuthProvider>
            <SettingsProvider>
              <CartProvider>
                <NetworkProvider>
                  <SafeAreaProvider>
                    <NetworkBanner />
                    <AppNavigator />
                  </SafeAreaProvider>
                </NetworkProvider>
              </CartProvider>
            </SettingsProvider>
          </AuthProvider>
        </StripeProvider>
      </LinearGradient>
    </GestureHandlerRootView>
  );

  // On web, wrap in a responsive centered container
  if (Platform.OS === 'web') {
    const maxW = getContainerMaxWidth(windowWidth);
    const needsWrapper = maxW !== undefined;

    if (!needsWrapper) {
      // Mobile web – full width, no extra wrapper
      return appContent;
    }

    return (
      <View style={styles.webOuterContainer}>
        <View style={[styles.webInnerContainer, { maxWidth: maxW }]}>
          {appContent}
        </View>
      </View>
    );
  }

  return appContent;
}

const styles = StyleSheet.create({
  loadingContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#fff',
  },
  gradient: {
    flex: 1,
  },
  webOuterContainer: {
    flex: 1,
    alignItems: 'center',
    backgroundColor: '#0a1520',
    height: '100%' as any,
  },
  webInnerContainer: {
    width: '100%',
    flex: 1,
    height: '100%' as any,
    overflow: 'hidden' as any,
    // Subtle shadow to separate from background
    ...(Platform.OS === 'web' ? {
      boxShadow: '0 0 40px rgba(0,0,0,0.5)',
    } as any : {}),
  },
});
